<script src="https://api.tomtom.com/maps-sdk-for-web/cdn/6.x/6.25.0/maps/maps-web.min.js"></script>
<script>
function weeklyBoard(initial,planId){return{candidates:initial||[],active:0,loading:false,map:null,drag:null,get current(){return this.candidates[this.active]||null},init(){this.$nextTick(()=>{this.initDrag();this.renderMap()})},fmt(v){return Number(v||0).toLocaleString('de-DE',{maximumFractionDigits:1})},money(v){return Number(v||0).toLocaleString('de-DE',{style:'currency',currency:'EUR'})},formatDate(v){return new Date(v+'T12:00:00').toLocaleDateString('de-DE',{weekday:'short',day:'2-digit',month:'2-digit'})},async generate(){this.loading=true;try{const r=await axios.post(`/sck/wochenplanung/${planId}/berechnen`);this.candidates=r.data.candidates;this.active=0;this.$nextTick(()=>{this.initDrag();this.renderMap()})}catch(e){alert(e.response?.data?.message||'Berechnung fehlgeschlagen')}finally{this.loading=false}},initDrag(){document.querySelectorAll('.weekly-stop').forEach(el=>el.ondragstart=()=>this.drag={tour:Number(el.dataset.tour),index:Number(el.dataset.index)});document.querySelectorAll('.tour-dropzone').forEach(zone=>{zone.ondragover=e=>e.preventDefault();zone.ondrop=e=>{e.preventDefault();if(!this.drag)return;const target=Number(zone.dataset.tour);const [stop]=this.current.tours[this.drag.tour].stops.splice(this.drag.index,1);this.current.tours[target].stops.push(stop);this.drag=null;this.save();this.$nextTick(()=>this.initDrag())}})},moveStop(tour,index,delta){const target=tour+delta;if(target<0||target>=this.current.tours.length)return;const [stop]=this.current.tours[tour].stops.splice(index,1);this.current.tours[target].stops.push(stop);this.save()},async save(){await axios.put(`/sck/wochenplanung/${planId}/kandidaten/${this.current.id}`,{tours:this.current.tours})},async recalculate(mode){this.loading=true;try{await this.save();const r=await axios.post(`/sck/wochenplanung/${planId}/kandidaten/${this.current.id}/neu-berechnen`,{mode});this.candidates[this.active]=r.data.candidate;this.$nextTick(()=>{this.initDrag();this.renderMap()})}catch(e){alert(e.response?.data?.message||'Neuberechnung fehlgeschlagen')}finally{this.loading=false}},materializeUrl(){return `/sck/wochenplanung/${planId}/kandidaten/${this.current.id}/uebernehmen`},renderMap(){if(!this.current||!window.tt||!@js(config('services.tomtom.key')))return;const container=document.getElementById('weekly-map');if(!container)return;if(this.map){this.map.remove();this.map=null}this.map=tt.map({key:@js(config('services.tomtom.key')),container,center:[@js((float)($weeklyPlan->stops->first()?->longitude ?? 6.06)),@js((float)($weeklyPlan->stops->first()?->latitude ?? 51.0))],zoom:8,style:document.documentElement.getAttribute('data-theme')==='light'?undefined:'https://api.tomtom.com/style/1/style/22.2.1-9?map=basic_night'});const colors=['#f97316','#06b6d4','#8b5cf6','#10b981','#ef4444','#eab308'];this.map.on('load',()=>{this.current.tours.forEach((tour,i)=>{const pts=tour.polyline||[];if(pts.length){this.map.addSource('route'+i,{type:'geojson',data:{type:'Feature',geometry:{type:'LineString',coordinates:pts.map(p=>[p.lng,p.lat])}}});this.map.addLayer({id:'route'+i,type:'line',source:'route'+i,paint:{'line-color':colors[i%colors.length],'line-width':4}})}tour.stops.forEach(s=>new tt.Marker({color:colors[i%colors.length]}).setLngLat([s.lng,s.lat]).setPopup(new tt.Popup().setText(s.title)).addTo(this.map))})})}}}
const baseWeeklyBoard=weeklyBoard;
weeklyBoard=function(initial,planId){const board=baseWeeklyBoard(initial,planId);board.initDrag=function(){const root=document.querySelector('[data-week-board]');if(!root||!this.current)return;document.querySelectorAll('.weekly-stop').forEach(el=>{el.tabIndex=0;el.title='Ziehen, Pfeiltasten zum Verschieben, Doppelklick zum Sperren';el.ondragstart=e=>{const stop=this.current.tours[Number(el.dataset.tour)].stops[Number(el.dataset.index)];if(stop.locked){e.preventDefault();return}this.drag={tour:Number(el.dataset.tour),index:Number(el.dataset.index)}};el.ondragover=e=>e.preventDefault();el.ondrop=e=>{e.preventDefault();if(!this.drag)return;const targetTour=Number(el.dataset.tour),targetIndex=Number(el.dataset.index),[stop]=this.current.tours[this.drag.tour].stops.splice(this.drag.index,1);let insert=targetIndex;if(this.drag.tour===targetTour&&this.drag.index<targetIndex)insert--;this.current.tours[targetTour].stops.splice(Math.max(0,insert),0,stop);this.drag=null;this.save();this.$nextTick(()=>this.initDrag())};el.ondblclick=()=>{const stop=this.current.tours[Number(el.dataset.tour)].stops[Number(el.dataset.index)];stop.locked=!stop.locked;el.classList.toggle('ring-2',stop.locked);this.save()};el.onkeydown=e=>{const tour=Number(el.dataset.tour),index=Number(el.dataset.index);if(e.key==='ArrowUp'&&index>0){e.preventDefault();const [stop]=this.current.tours[tour].stops.splice(index,1);this.current.tours[tour].stops.splice(index-1,0,stop);this.save()}else if(e.key==='ArrowDown'&&index<this.current.tours[tour].stops.length-1){e.preventDefault();const [stop]=this.current.tours[tour].stops.splice(index,1);this.current.tours[tour].stops.splice(index+1,0,stop);this.save()}else if(e.key==='ArrowLeft'||e.key==='ArrowRight'){e.preventDefault();this.moveStop(tour,index,e.key==='ArrowLeft'?-1:1)};this.$nextTick(()=>this.initDrag())}});document.querySelectorAll('.tour-dropzone').forEach(zone=>{zone.ondragover=e=>e.preventDefault();zone.ondrop=e=>{if(e.target.closest('.weekly-stop')||!this.drag)return;e.preventDefault();const target=Number(zone.dataset.tour),[stop]=this.current.tours[this.drag.tour].stops.splice(this.drag.index,1);this.current.tours[target].stops.push(stop);this.drag=null;this.save();this.$nextTick(()=>this.initDrag())}});const pool=root.querySelector(':scope > section:last-child');if(pool){pool.ondragover=e=>e.preventDefault();pool.ondrop=e=>{e.preventDefault();if(!this.drag)return;const [stop]=this.current.tours[this.drag.tour].stops.splice(this.drag.index,1);this.current.unassigned=this.current.unassigned||[];this.current.unassigned.push({...stop,reason:'Manuell nicht zugeordnet.'});this.drag=null;this.save();this.$nextTick(()=>this.initDrag())};pool.querySelectorAll('.space-y-2 > div').forEach((entry,index)=>{if(entry.querySelector('button'))return;const button=document.createElement('button');button.type='button';button.className='text-xs text-cyan-400 mt-1';button.textContent='In Tour 1 verschieben';button.onclick=()=>{const [stop]=this.current.unassigned.splice(index,1);this.current.tours[0].stops.push(stop);this.save();this.$nextTick(()=>this.initDrag())};entry.appendChild(button)})}};return board};
const dragWeeklyBoard=weeklyBoard;weeklyBoard=function(initial,planId){const board=dragWeeklyBoard(initial,planId),baseMove=board.moveStop;board.save=async function(){await axios.put(`/sck/wochenplanung/${planId}/kandidaten/${this.current.id}`,{tours:this.current.tours,unassigned:this.current.unassigned||[]})};board.moveStop=function(tour,index,delta){if(this.current.tours[tour].stops[index]?.locked)return;baseMove.call(this,tour,index,delta)};return board};
</script>
@endpush
